<?php $metaTitle='Forgot Password'; include __DIR__.'/includes/header.php'; if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf($_POST['csrf_token']??'')) die('Invalid CSRF'); $token=bin2hex(random_bytes(32)); $db->prepare('INSERT INTO password_resets(email,token,expires_at,created_at) VALUES(?,?,DATE_ADD(NOW(), INTERVAL 1 HOUR),NOW())')->execute([sanitize($_POST['email']),$token]); flash('success','Reset link generated for demo: /reset-password.php?token='.$token); redirect('/forgot-password.php');}
?>
<section class="container py-5" style="max-width:520px"><h1>Forgot Password</h1><?php if($m=flash('success')):?><div class="alert alert-info"><?=e($m)?></div><?php endif;?><form method="post" class="card card-body"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="email" required name="email" class="form-control mb-3" placeholder="Registered email"><button class="btn btn-primary">Send Reset Link</button></form></section>
